// CRC model catalogue — all preset models used by crc.html
// Depends on createModel() exposed by crc.min.js (loaded first)
// Parameters from the CRC RevEng catalogue: https://reveng.sourceforge.io/crc-catalogue/
!function(w){
function m(n,p){w[n]=createModel(p);}
// CRC-3
m('crc_3_gsm',    {width:3, poly:0x3,       init:0x0,       refin:false,refout:false,xorout:0x7});
m('crc_3_rohc',   {width:3, poly:0x3,       init:0x7,       refin:true, refout:true, xorout:0x0});
// CRC-4
m('crc_4_g_704',  {width:4, poly:0x3,       init:0x0,       refin:true, refout:true, xorout:0x0});
// CRC-5
m('crc_5_usb',    {width:5, poly:0x05,      init:0x1f,      refin:true, refout:true, xorout:0x1f});
// CRC-7
m('crc_7_mmc',    {width:7, poly:0x09,      init:0x00,      refin:false,refout:false,xorout:0x00});
// CRC-8
m('crc_8_smbus',      {width:8, poly:0x07,  init:0x00,      refin:false,refout:false,xorout:0x00});
m('crc_8_autosar',    {width:8, poly:0x2f,  init:0xff,      refin:false,refout:false,xorout:0xff});
m('crc_8_bluetooth',  {width:8, poly:0xa7,  init:0x00,      refin:true, refout:true, xorout:0x00});
m('crc_8_dvb_s2',     {width:8, poly:0xd5,  init:0x00,      refin:false,refout:false,xorout:0x00});
m('crc_8_maxim_dow',  {width:8, poly:0x31,  init:0x00,      refin:true, refout:true, xorout:0x00});
// CRC-10
m('crc_10_atm',   {width:10,poly:0x233,     init:0x000,     refin:false,refout:false,xorout:0x000});
// CRC-12
m('crc_12_dect',  {width:12,poly:0x80f,     init:0x000,     refin:false,refout:false,xorout:0x000});
// CRC-16
m('crc_16_arc',       {width:16,poly:0x8005,init:0x0000,    refin:true, refout:true, xorout:0x0000});
m('crc_16_cdma2000',  {width:16,poly:0xc867,init:0xffff,    refin:false,refout:false,xorout:0x0000});
m('crc_16_ibm_3740',  {width:16,poly:0x1021,init:0xffff,    refin:false,refout:false,xorout:0x0000});
m('crc_16_kermit',    {width:16,poly:0x1021,init:0x0000,    refin:true, refout:true, xorout:0x0000});
m('crc_16_modbus',    {width:16,poly:0x8005,init:0xffff,    refin:true, refout:true, xorout:0x0000});
m('crc_16_xmodem',    {width:16,poly:0x1021,init:0x0000,    refin:false,refout:false,xorout:0x0000});
// CRC-24
m('crc_24_openpgp',{width:24,poly:0x864cfb, init:0xb704ce,  refin:false,refout:false,xorout:0x000000});
// CRC-32
m('crc_32_iso_hdlc',{width:32,poly:0x04c11db7,init:0xffffffff,refin:true, refout:true, xorout:0xffffffff});
m('crc_32_bzip2',   {width:32,poly:0x04c11db7,init:0xffffffff,refin:false,refout:false,xorout:0xffffffff});
m('crc_32_iscsi',   {width:32,poly:0x1edc6f41,init:0xffffffff,refin:true, refout:true, xorout:0xffffffff});
m('crc_32_mpeg_2',  {width:32,poly:0x04c11db7,init:0xffffffff,refin:false,refout:false,xorout:0x00000000});
// CRC-64  (poly / init / xorout as [hi32, lo32] arrays)
// CRC-64/ECMA-182: poly=0x42F0E1EBA9EA3693
m('crc_64_ecma_182',{width:64,poly:[0x42f0e1eb,0xa9ea3693],init:[0,0],          refin:false,refout:false,xorout:[0,0]});
// CRC-64/GO-ISO:   poly=0x000000000000001B, init=0xFFFFFFFFFFFFFFFF
m('crc_64_go_iso',  {width:64,poly:[0x00000000,0x0000001b],init:[0xffffffff,0xffffffff],refin:true, refout:true, xorout:[0xffffffff,0xffffffff]});
// CRC-64/REDIS:    poly=0xAD93D23594C935A9
m('crc_64_redis',   {width:64,poly:[0xad93d235,0x94c935a9],init:[0,0],          refin:true, refout:true, xorout:[0,0]});
// CRC-64/XZ:       poly=0x42F0E1EBA9EA3693, init=0xFFFFFFFFFFFFFFFF
m('crc_64_xz',      {width:64,poly:[0x42f0e1eb,0xa9ea3693],init:[0xffffffff,0xffffffff],refin:true, refout:true, xorout:[0xffffffff,0xffffffff]});
}(window);
